class Solution {
public:
    int minStartingIndex(string s, string pattern) {
        int n = s.size();
        int m = pattern.size();
        int diff = 0;
        for (int i = 0; i < m; i++) {
            if (s[i] != pattern[i]) {
                diff++;
            }
        }
        if (diff > 1) {
            return -1;
        }
        int minIndex = n;
        for (int i = 0; i <= n - m; i++) {
            int curDiff = 0;
            for (int j = 0; j < m; j++) {
                if (s[i + j] != pattern[j]) {
                    curDiff++;
                }
            }
            if (curDiff <= 1) {
                minIndex = min(minIndex, i);
            }
        }
        return minIndex == n ? -1 : minIndex;
    }
};
